DECLARE @roomId BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 01');
DECLARE @row CHAR(1), @col INT, @seatType NVARCHAR(20);
DECLARE @rows TABLE (label CHAR(1), idx INT);
INSERT INTO @rows VALUES ('A',1),('B',2),('C',3),('D',4),('E',5),('F',6),('G',7),('H',8);

DECLARE row_cursor CURSOR FOR SELECT label, idx FROM @rows;
OPEN row_cursor;
FETCH NEXT FROM row_cursor INTO @row, @col;
WHILE @@FETCH_STATUS = 0
BEGIN
    SET @col = 1;
    WHILE @col <= 10
    BEGIN
        SET @seatType = CASE
            WHEN @row IN ('D','E') THEN 'VIP'
            WHEN @row = 'H' THEN 'COUPLE'
            ELSE 'STANDARD'
        END;
        INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, version, storage_state, created_by, created_at, updated_at)
        VALUES (@roomId, @row, @col, @row + CAST(@col AS VARCHAR), @seatType, 'ACTIVE', 0, 'ACTIVE', 'system', GETDATE(), GETDATE());
        SET @col = @col + 1;
    END;
    FETCH NEXT FROM row_cursor INTO @row, @col;
END;
CLOSE row_cursor;
DEALLOCATE row_cursor;

DECLARE @roomId2 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 02');
DECLARE @row2 CHAR(1), @col2 INT, @seatType2 NVARCHAR(20);
DECLARE @rows2 TABLE (label CHAR(1));
INSERT INTO @rows2 VALUES ('A'),('B'),('C'),('D'),('E'),('F');

DECLARE row_cursor2 CURSOR FOR SELECT label FROM @rows2;
OPEN row_cursor2;
FETCH NEXT FROM row_cursor2 INTO @row2;
WHILE @@FETCH_STATUS = 0
BEGIN
    SET @col2 = 1;
    WHILE @col2 <= 10
    BEGIN
        SET @seatType2 = CASE WHEN @row2 IN ('C','D') THEN 'VIP' ELSE 'STANDARD' END;
        INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, version, storage_state, created_by, created_at, updated_at)
        VALUES (@roomId2, @row2, @col2, @row2 + CAST(@col2 AS VARCHAR), @seatType2, 'ACTIVE', 0, 'ACTIVE', 'system', GETDATE(), GETDATE());
        SET @col2 = @col2 + 1;
    END;
    FETCH NEXT FROM row_cursor2 INTO @row2;
END;
CLOSE row_cursor2;
DEALLOCATE row_cursor2;

DECLARE @movie1 BIGINT = (SELECT id FROM movies WHERE title = N'Lật Mặt 7: Một Điều Ước'); DECLARE @movie2 BIGINT = (SELECT id FROM movies WHERE title = 'Thunderbolts*'); DECLARE @movie3 BIGINT = (SELECT id FROM movies WHERE title = N'Quỷ Cẩu'); DECLARE @movie4 BIGINT = (SELECT id FROM movies WHERE title = 'Mission: Impossible - The Final Reckoning'); DECLARE @movie5 BIGINT = (SELECT id FROM movies WHERE title = N'Doraemon: Nobita và Vùng Đất Lý Tưởng Trên Bầu Trời'); DECLARE @room1 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 01'); DECLARE @room2 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 02'); DECLARE @room3 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng IMAX');
-- Lật Mặt 7: hôm nay 14:00, 19:00 INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie1, @room1, DATEADD(hour, 14, CAST(CAST(GETDATE() AS DATE) AS DATETIME2)), DATEADD(hour, 16, CAST(CAST(GETDATE() AS DATE) AS DATETIME2)), 75000, 95000, 160000, 'SCHEDULED', 0, 'ACTIVE', 'system', GETDATE(), GETDATE()); INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie1, @room1, DATEADD(hour, 19, CAST(CAST(GETDATE() AS DATE) AS DATETIME2)), DATEADD(hour, 21, CAST(CAST(GETDATE() AS DATE) AS DATETIME2)), 85000, 105000, 180000, 'SCHEDULED', 0, 'ACTIVE', 'system', GETDATE(), GETDATE());
-- Thunderbolts*: hôm nay 15:30, ngày mai 10:00 INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie2, @room2, DATEADD(minute, 930, CAST(CAST(GETDATE() AS DATE) AS DATETIME2)), DATEADD(minute, 1057, CAST(CAST(GETDATE() AS DATE) AS DATETIME2)), 90000, 120000, 200000, 'SCHEDULED', 0, 'ACTIVE', 'system', GETDATE(), GETDATE()); INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie2, @room2, DATEADD(hour, 10, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), DATEADD(minute, 727, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), 90000, 120000, 200000, 'SCHEDULED', 0, 'ACTIVE', 'system', GETDATE(), GETDATE());
-- Mission Impossible: IMAX, ngày mai 18:00 INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie4, @room3, DATEADD(hour, 18, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), DATEADD(minute, 1249, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), 120000, 160000, 280000, 'SCHEDULED', 0, 'ACTIVE', 'system', GETDATE(), GETDATE());
-- Quỷ Cẩu: ngày mai 20:00 INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie3, @room1, DATEADD(hour, 20, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), DATEADD(minute, 1308, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), 75000, 95000, 160000, 'SCHEDULED', 0, 'ACTIVE', 'system', GETDATE(), GETDATE());
-- Doraemon: ngày mai 09:00 INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie5, @room2, DATEADD(hour, 9, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), DATEADD(minute, 648, CAST(CAST(DATEADD(day, 1, GETDATE()) AS DATE) AS DATETIME2)), 65000, 85000, 140000, 'SCHEDULED', 0, 'ACTIVE', 'system', GETDATE(), GETDATE());
-- Suất chiếu quá khứ (đã hoàn thành) — cho dữ liệu doanh thu -- Lật Mặt 7: 3 ngày trước INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie1, @room1, DATEADD(hour, 19, CAST(CAST(DATEADD(day, -3, GETDATE()) AS DATE) AS DATETIME2)), DATEADD(hour, 21, CAST(CAST(DATEADD(day, -3, GETDATE()) AS DATE) AS DATETIME2)), 75000, 95000, 160000, 'FINISHED', 0, 'ACTIVE', 'system', DATEADD(day, -4, GETDATE()), DATEADD(day, -3, GETDATE())); -- Thunderbolts: 2 ngày trước INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie2, @room2, DATEADD(hour, 20, CAST(CAST(DATEADD(day, -2, GETDATE()) AS DATE) AS DATETIME2)), DATEADD(hour, 22, CAST(CAST(DATEADD(day, -2, GETDATE()) AS DATE) AS DATETIME2)), 90000, 120000, 200000, 'FINISHED', 0, 'ACTIVE', 'system', DATEADD(day, -3, GETDATE()), DATEADD(day, -2, GETDATE())); -- MI: 1 ngày trước INSERT INTO showtimes (movie_id, room_id, start_time, end_time, base_price, vip_price, couple_price, status, version, storage_state, created_by, created_at, updated_at) VALUES (@movie4, @room3, DATEADD(hour, 18, CAST(CAST(DATEADD(day, -1, GETDATE()) AS DATE) AS DATETIME2)), DATEADD(hour, 21, CAST(CAST(DATEADD(day, -1, GETDATE()) AS DATE) AS DATETIME2)), 120000, 160000, 280000, 'FINISHED', 0, 'ACTIVE', 'system', DATEADD(day, -2, GETDATE()), DATEADD(day, -1, GETDATE()));

