VALUES (@userA, @st_lm7_past, 265000, 'CHECKED_IN', 'CX-240521-001',
    DATEADD(day, -3, GETDATE()), 0, 'ACTIVE', 'system',
    DATEADD(day, -3, GETDATE()), DATEADD(day, -3, GETDATE()));

